{% endif %}

{% if incident.jira_issue_url != blank %}
  ![Jira Issue!]({{ images.jira_url_16 }}) [Jira Issue]({{ incident.jira_issue_url }})
{% endif %}

{% if incident.asana_task_url != blank %}
